// scripts/generate-item-icons.mjs
//
// Batch-generate商品图标 from icon-prompts.md + scripts/data/item-catalog.mjs via
// Gemini / Imagen, into a staging dir, review via a contact sheet, then promote
// the keepers into public/icons/.
//
// Prereq: GEMINI_API_KEY must be set. Run with node's env-file loader:
//   node --env-file=.env scripts/generate-item-icons.mjs --limit 3
//
// Common flows:
//   # generate all not-yet-generated items (default model: gemini-2.5-flash-image)
//   node --env-file=.env scripts/generate-item-icons.mjs
//   # compare models on 5 items — each item generated by every model, side-by-side in the sheet
//   node --env-file=.env scripts/generate-item-icons.mjs --limit 5 --model gemini-3-pro-image,imagen-4.0-ultra-generate-001
//   # (re)generate specific items with one model
//   node --env-file=.env scripts/generate-item-icons.mjs --only apple,banana --force --model gemini-3-pro-image
//   # after reviewing icon-staging/contact-sheet.html, promote one model's versions
//   node scripts/generate-item-icons.mjs --promote all --model gemini-3-pro-image
//
// Models: gemini-2.5-flash-image, gemini-3.1-flash-image, gemini-3-pro-image,
//         imagen-4.0-fast-generate-001, imagen-4.0-generate-001, imagen-4.0-ultra-generate-001

import { parseIconPrompts } from './lib/parse-icon-prompts.mjs';
import catalog from './data/item-catalog.mjs';
import {
  readFileSync, writeFileSync, mkdirSync, existsSync, readdirSync, copyFileSync,
} from 'node:fs';
import { resolve, join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import sharp from 'sharp';

const ROOT = resolve(dirname(fileURLToPath(import.meta.url)), '..');
const PROMPTS_PATH = join(ROOT, 'icon-prompts.md');
const ICONS_DIR = join(ROOT, 'public', 'icons');
const STAGING_DIR = join(ROOT, 'icon-staging');
const REGISTRY_PATH = join(ROOT, 'src', 'utils', 'icon-registry.ts');

const DEFAULT_MODEL = 'gemini-2.5-flash-image';
const TARGET_SIZE = 512;
const QUALITY = 85;
const MAX_RETRIES = 1;

const STYLE_TEMPLATE = `生成一个手绘素描+柔和上色风格的商品图标：

物品：{item}
风格要求：
- 铅笔线稿描边，线条自然有手绘感
- 水彩/彩铅柔和上色，保留笔触和晕染感
- 像精致插画书里的插图
- 纯白背景，物体居中，占画面 70-80%
- 256×256 正方形，无文字无装饰无阴影
- 包装上不要出现任何文字和 logo`;

// prompt-category (from icon-prompts.md) → icon-registry category
const CATEGORY_MAP = {
  '蔬菜': '蔬菜', '蔬菜补充': '蔬菜',
  '肉类': '肉蛋', '蛋奶': '肉蛋',
  '主食': '主食', '主食补充': '主食',
  '调料': '调料',
  '日用品': '日用',
  '烘焙': '烘焙',
  '饮料': '饮料',
  '乳制品补充': '乳制品',
};
// categories the WatercolorFallback already has colors for
const KNOWN_CATEGORIES = new Set(['蔬菜', '肉蛋', '乳制品', '饮料', '主食', '调料', '日用', '烘焙']);

const TAGS = {
  'gemini-2.5-flash-image': 'flash',
  'gemini-3.1-flash-image': 'flash31',
  'gemini-3-pro-image': 'pro',
  'imagen-4.0-fast-generate-001': 'imagen-fast',
  'imagen-4.0-generate-001': 'imagen-std',
  'imagen-4.0-ultra-generate-001': 'imagen-ultra',
};
const modelTag = (model) => TAGS[model] || model.replace(/[^a-z0-9]+/gi, '-').slice(0, 16);
const isImagen = (model) => model.startsWith('imagen');

function parseArgs(argv) {
  const args = { limit: null, only: null, force: false, promote: null, models: null };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === '--limit') args.limit = Number(argv[++i]);
    else if (a === '--only') args.only = argv[++i].split(',').map(s => s.trim()).filter(Boolean);
    else if (a === '--force') args.force = true;
    else if (a === '--promote') args.promote = argv[++i];
    else if (a === '--model') args.models = argv[++i].split(',').map(s => s.trim()).filter(Boolean);
    else if (a === '--help' || a === '-h') args.help = true;
  }
  return args;
}

function buildPrompt(item) {
  return STYLE_TEMPLATE.replace('{item}', item.desc || item.name);
}

// Merge hand-tuned icon-prompts.md items with the bulk catalog, deduped by stem
// (icon-prompts.md wins so its hand-tuned prompts are preserved).
function loadItems() {
  const md = parseIconPrompts(readFileSync(PROMPTS_PATH, 'utf8'));
  const seen = new Set(md.map(i => i.stem));
  const fromCatalog = catalog
    .filter(c => !seen.has(c.stem))
    .map(c => ({ name: c.name, stem: c.stem, category: c.category, prompt: buildPrompt(c) }));
  return [...md, ...fromCatalog];
}

function generatedStems() {
  if (!existsSync(ICONS_DIR)) return new Set();
  return new Set(
    readdirSync(ICONS_DIR).filter(f => f.endsWith('.webp')).map(f => f.replace(/\.webp$/, ''))
  );
}

async function callModel(prompt, model) {
  const key = process.env.GEMINI_API_KEY;
  if (!key) {
    throw new Error(
      'GEMINI_API_KEY not set. Run with: node --env-file=.env scripts/generate-item-icons.mjs ...'
    );
  }
  const base = `https://generativelanguage.googleapis.com/v1beta/models/${model}`;

  if (isImagen(model)) {
    const res = await fetch(`${base}:predict?key=${key}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        instances: [{ prompt }],
        parameters: { sampleCount: 1, aspectRatio: '1:1' },
      }),
    });
    if (!res.ok) throw new Error(`Imagen HTTP ${res.status}: ${(await res.text()).slice(0, 300)}`);
    const data = await res.json();
    const b64 = data?.predictions?.[0]?.bytesBase64Encoded;
    if (!b64) throw new Error('No image in Imagen response');
    return Buffer.from(b64, 'base64');
  }

  // Gemini image models (:generateContent)
  const res = await fetch(`${base}:generateContent?key=${key}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      contents: [{ parts: [{ text: prompt }] }],
      generationConfig: { responseModalities: ['IMAGE'], imageConfig: { aspectRatio: '1:1' } },
    }),
  });
  if (!res.ok) throw new Error(`Gemini HTTP ${res.status}: ${(await res.text()).slice(0, 300)}`);
  const data = await res.json();
  const parts = data?.candidates?.[0]?.content?.parts ?? [];
  const part = parts.find(p => p.inline_data?.data || p.inlineData?.data);
  const b64 = part?.inline_data?.data ?? part?.inlineData?.data;
  if (!b64) throw new Error('No image in Gemini response');
  return Buffer.from(b64, 'base64');
}

async function generateOne(item, model) {
  const tag = modelTag(model);
  let lastErr;
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      const png = await callModel(item.prompt, model);
      const baseName = `${item.stem}__${tag}`;
      writeFileSync(join(STAGING_DIR, `${baseName}.png`), png);
      await sharp(png)
        .resize(TARGET_SIZE, TARGET_SIZE, { fit: 'inside', withoutEnlargement: true })
        .webp({ quality: QUALITY })
        .toFile(join(STAGING_DIR, `${baseName}.webp`));
      return true;
    } catch (err) {
      lastErr = err;
      if (attempt < MAX_RETRIES) console.log(`    retry (${err.message})`);
    }
  }
  console.log(`  ✗ ${item.stem} [${tag}] — ${lastErr.message}`);
  return false;
}

// staging webp files are named `${stem}__${tag}.webp`
function stagedVariants() {
  if (!existsSync(STAGING_DIR)) return {};
  const groups = {};
  for (const f of readdirSync(STAGING_DIR).filter(f => f.endsWith('.webp'))) {
    const m = f.match(/^(.+)__([a-z0-9-]+)\.webp$/);
    const stem = m ? m[1] : f.replace(/\.webp$/, '');
    const tag = m ? m[2] : '';
    (groups[stem] ??= []).push({ tag, file: f });
  }
  return groups;
}

function writeContactSheet(items) {
  const byStem = new Map(items.map(i => [i.stem, i]));
  const groups = stagedVariants();
  const cards = Object.keys(groups).sort().map(stem => {
    const it = byStem.get(stem);
    const name = it ? it.name : stem;
    const cat = it ? (it.category ?? '') : '';
    const variants = [];
    // show the already-published icon (if any) as the style benchmark
    if (existsSync(join(ICONS_DIR, `${stem}.webp`))) {
      variants.push({ label: '现有', src: `../public/icons/${stem}.webp`, current: true });
    }
    for (const v of groups[stem].sort((a, b) => a.tag.localeCompare(b.tag))) {
      variants.push({ label: v.tag, src: v.file });
    }
    const vhtml = variants.map(v => `
      <div class="variant${v.current ? ' current' : ''}"><div class="box"><img src="${v.src}" alt="${name}"/></div><span class="tag">${v.label}</span></div>`).join('');
    return `<figure><figcaption><b>${name}</b><span>${stem} · ${cat}</span></figcaption><div class="variants">${vhtml}</div></figure>`;
  }).join('\n');

  const html = `<!doctype html><html lang="zh"><head><meta charset="utf-8"/>
<title>图标接触印相表</title>
<style>
  body{margin:0;padding:24px;background:linear-gradient(180deg,#faf6f0,#f3ede4);font-family:system-ui,"PingFang SC","Microsoft YaHei",sans-serif;color:#5a4e3c}
  h1{font-size:16px;margin:0 0 4px}
  p{font-size:12px;color:#a0937e;margin:0 0 20px}
  .grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:14px}
  figure{margin:0;background:rgba(255,252,247,.7);border:1px solid rgba(215,205,188,.4);border-radius:14px;padding:10px}
  figcaption{font-size:12px;text-align:center;margin-bottom:8px}
  figcaption span{display:block;font-size:10px;color:#a0937e;margin-top:2px}
  .variants{display:flex;gap:8px;justify-content:center}
  .variant{flex:1;max-width:120px;text-align:center}
  .box{aspect-ratio:1;background:#fff;border-radius:10px;display:flex;align-items:center;justify-content:center;overflow:hidden}
  .box img{width:100%;height:100%;object-fit:contain;mix-blend-mode:multiply}
  .tag{display:block;font-size:9px;color:#7ca982;font-weight:700;margin-top:4px}
  .variant.current .box{border:2px solid #7ca982}
  .variant.current .tag{color:#5a4e3c}
</style></head><body>
<h1>图标接触印相表</h1>
<p>同一物品并排对比；标「现有」、绿框的是 public/icons 里已发布的版本（风格基准）。选定后：<code>node scripts/generate-item-icons.mjs --promote all --model &lt;模型&gt;</code></p>
<div class="grid">${cards}</div>
</body></html>`;
  writeFileSync(join(STAGING_DIR, 'contact-sheet.html'), html);
}

async function runGenerate(args) {
  const items = loadItems();
  const have = generatedStems();
  let targets;
  if (args.only) {
    const set = new Set(args.only);
    targets = items.filter(i => set.has(i.stem));
    const missing = args.only.filter(s => !items.some(i => i.stem === s));
    if (missing.length) console.log(`⚠ not found: ${missing.join(', ')}`);
  } else {
    targets = args.force ? items : items.filter(i => !have.has(i.stem));
  }
  if (args.limit != null) targets = targets.slice(0, args.limit);

  if (!targets.length) {
    console.log('Nothing to generate (all present? use --force or --only).');
    return;
  }

  const models = args.models ?? [DEFAULT_MODEL];
  mkdirSync(STAGING_DIR, { recursive: true });
  console.log(`Generating ${targets.length} item(s) × ${models.length} model(s) [${models.map(modelTag).join(', ')}] → ${STAGING_DIR}\n`);

  let ok = 0, total = 0;
  for (const item of targets) {
    for (const model of models) {
      total++;
      process.stdout.write(`  · ${item.stem} (${item.name}) [${modelTag(model)}] … `);
      const success = await generateOne(item, model);
      if (success) { ok++; console.log('✓'); }
    }
  }

  writeContactSheet(items);
  console.log(`\nDone: ${ok}/${total} generated.`);
  console.log(`Review:  ${join(STAGING_DIR, 'contact-sheet.html')}`);
  console.log(`Promote: node scripts/generate-item-icons.mjs --promote all --model <chosen-model>`);
}

function buildRegistryEntries(stems, items) {
  const byStem = new Map(items.map(i => [i.stem, i]));
  const entries = [];
  const newCats = new Set();
  for (const stem of stems) {
    const it = byStem.get(stem);
    if (!it) { console.log(`⚠ ${stem}: not in catalog/prompts, skipping registry entry`); continue; }
    const cat = CATEGORY_MAP[it.category] ?? it.category ?? '其他';
    if (!KNOWN_CATEGORIES.has(cat)) newCats.add(cat);
    entries.push({ stem, name: it.name, category: cat });
  }
  return { entries, newCats };
}

function runPromote(args, items) {
  const groups = stagedVariants();
  if (!Object.keys(groups).length) { console.log('No staging dir / nothing staged. Generate first.'); return; }

  let chosenTag = null;
  if (args.models && args.models.length === 1) chosenTag = modelTag(args.models[0]);
  else if (args.models && args.models.length > 1) { console.log('Pass a single --model to promote.'); return; }

  const stems = args.promote === 'all'
    ? Object.keys(groups)
    : args.promote.split(',').map(s => s.trim()).filter(Boolean);

  mkdirSync(ICONS_DIR, { recursive: true });
  const promoted = [];
  for (const stem of stems) {
    const vs = groups[stem];
    if (!vs) { console.log(`⚠ ${stem}: not in staging, skip`); continue; }
    let chosen;
    if (chosenTag) {
      chosen = vs.find(v => v.tag === chosenTag);
      if (!chosen) { console.log(`⚠ ${stem}: no "${chosenTag}" variant, skip`); continue; }
    } else if (vs.length === 1) {
      chosen = vs[0];
    } else {
      console.log(`⚠ ${stem}: multiple variants [${vs.map(v => v.tag).join(', ')}], pass --model to pick`);
      continue;
    }
    copyFileSync(join(STAGING_DIR, chosen.file), join(ICONS_DIR, `${stem}.webp`));
    promoted.push(stem);
  }
  if (!promoted.length) { console.log('Nothing promoted.'); return; }
  console.log(`Copied ${promoted.length} → public/icons/: ${promoted.join(', ')}`);

  // register in icon-registry.ts
  const { entries, newCats } = buildRegistryEntries(promoted, items);
  let reg = readFileSync(REGISTRY_PATH, 'utf8');
  const fresh = entries.filter(e => !new RegExp(`icon:\\s*'${e.stem}'`).test(reg));
  const lines = fresh.map(e => `  { name: '${e.name}', icon: '${e.stem}', category: '${e.category}' },`).join('\n');

  console.log('\nRegistry entries:');
  console.log(fresh.length ? lines : '  (all already registered)');

  if (fresh.length) {
    const anchor = '\nexport const UNIQUE_ICON_ITEMS = ICON_ITEMS;';
    const close = reg.lastIndexOf('];', reg.indexOf(anchor));
    if (close !== -1) {
      reg = reg.slice(0, close) + lines + '\n' + reg.slice(close);
      writeFileSync(REGISTRY_PATH, reg);
      console.log(`\n✓ Inserted ${fresh.length} entries into icon-registry.ts`);
    } else {
      console.log('\n⚠ Could not locate ICON_ITEMS array end — paste the entries above manually.');
    }
  }
  if (newCats.size) {
    console.log(`\n⚠ New categories: ${[...newCats].join(', ')}`);
    console.log('  → add a watercolor color for each in WatercolorFallback before they look right.');
  }
}

async function main() {
  const args = parseArgs(process.argv.slice(2));
  if (args.help) {
    console.log('See header comment in scripts/generate-item-icons.mjs for usage.');
    return;
  }
  if (args.promote) runPromote(args, loadItems());
  else await runGenerate(args);
}

main().catch(err => { console.error(err); process.exit(1); });
